function renderSpecsToDiv(specsDiv, specs) {
  if (!specs || !specs.categories || specs.total_symbols === 0) {
    specsDiv.innerHTML = `<div style="color:#888">No symbol specs available yet (BarCacheWriter v1.300+ required)</div>`;
    return;
  }

  const catColors = { Forex: "#2196f3", Crypto: "#9c27b0", Commodities: "#ff9800", Indices: "#00bcd4" };
  let html = `<div style="color:#4caf50;font-weight:bold;margin-bottom:4px">${specs.total_symbols} symbols | ${specs.total_bar_keys} bar entries synced</div>`;

  // Category progress bars
  for (const cat of specs.categories) {
    const pct = cat.total > 0 ? Math.round((cat.complete / cat.total) * 100) : 0;
    const partialPct = cat.total > 0 ? Math.round((cat.partial / cat.total) * 100) : 0;
    const color = catColors[cat.category] || "#888";
    html += `<div style="margin:2px 0;display:flex;align-items:center;gap:6px">`;
    html += `<span style="color:${color};width:100px;display:inline-block">${cat.category}</span>`;
    // Mini progress bar
    html += `<div style="background:#222;width:120px;height:10px;border-radius:2px;overflow:hidden;display:inline-flex">`;
    html += `<div style="background:#4caf50;width:${pct}%;height:100%"></div>`;
    html += `<div style="background:#ff9800;width:${partialPct}%;height:100%"></div>`;
    html += `</div>`;
    html += `<span style="color:#4caf50">${cat.complete}</span>`;
    html += `<span style="color:#888">/</span>`;
    html += `<span style="color:${color}">${cat.total}</span>`;
    html += `<span style="color:#888;font-size:9px">complete</span>`;
    if (cat.partial > 0) html += `<span style="color:#ff9800;font-size:9px">${cat.partial} partial</span>`;
    if (cat.none > 0) html += `<span style="color:#666;font-size:9px">${cat.none} pending</span>`;
    html += `</div>`;
  }

  // Expandable per-symbol details
  const grouped = {};
  for (const sym of (specs.symbols || [])) {
    const cat = sym.category || "Other";
    if (!grouped[cat]) grouped[cat] = [];
    grouped[cat].push(sym);
  }

  html += `<div style="margin-top:6px">`;
  for (const [cat, syms] of Object.entries(grouped)) {
    const color = catColors[cat] || "#888";
    const complete = syms.filter(s => s.status === "complete");
    const partial = syms.filter(s => s.status === "partial");
    const none = syms.filter(s => s.status === "none");

    if (partial.length > 0) {
      html += `<div style="color:${color};margin-top:3px">${cat} in progress:</div>`;
      for (const s of partial) {
        const tfs = s.synced_tfs || [];
        const missing = ["1Month","1Week","1Day","4Hour","1Hour","30Min","15Min","5Min","1Min"].filter(t => !tfs.includes(t));
        html += `<div style="color:#ff9800;margin-left:8px">${s.normalized} ${s.synced_count}/${s.total_tfs} TFs`;
        if (missing.length <= 4) html += ` <span style="color:#666;font-size:9px">need: ${missing.join(", ")}</span>`;
        html += `</div>`;
      }
    }
    if (complete.length > 0) {
      html += `<div style="color:${color};margin-top:3px">${cat} complete (${complete.length}):</div>`;
      html += `<div style="color:#4caf50;margin-left:8px;font-size:9px">${complete.map(s => s.normalized).join(", ")}</div>`;
    }
    if (none.length > 0 && none.length <= 20) {
      html += `<div style="color:${color};margin-top:3px">${cat} pending (${none.length}):</div>`;
      html += `<div style="color:#666;margin-left:8px;font-size:9px">${none.map(s => s.normalized).join(", ")}</div>`;
    } else if (none.length > 20) {
      html += `<div style="color:#666;margin-top:3px">${cat} pending: ${none.length} symbols</div>`;
    }
  }
  html += `</div>`;

  specsDiv.innerHTML = html;
}

async function showSpecsSyncProgress(addLog) {
  try {
    const specs = JSON.parse(await invoke("get_mt5_specs"));
    if (!specs || !specs.categories) return;

    addLog(`<b>Symbol Sync Progress</b> (${specs.total_symbols} total symbols, ${specs.total_bar_keys} bar entries)`, "#4caf50");
    addLog("");

    // Category summary with progress bars
    const catColors = { Forex: "#2196f3", Crypto: "#9c27b0", Commodities: "#ff9800", Indices: "#00bcd4" };
    for (const cat of specs.categories) {
      const pct = cat.total > 0 ? Math.round((cat.complete / cat.total) * 100) : 0;
      const color = catColors[cat.category] || "#888";
      const bar = "\u2588".repeat(Math.round(pct / 5)) + "\u2591".repeat(20 - Math.round(pct / 5));
      addLog(`  <span style="color:${color}">${cat.category.padEnd(14)}</span> ${bar} ${String(cat.complete).padStart(4)}/${String(cat.total).padStart(4)} complete | ${cat.partial} partial | ${cat.none} pending`, color);
    }
    addLog("");

    // Show symbols by category with sync status
    const grouped = {};
    for (const sym of (specs.symbols || [])) {
      const cat = sym.category || "Other";
      if (!grouped[cat]) grouped[cat] = [];
      grouped[cat].push(sym);
    }

    for (const [cat, syms] of Object.entries(grouped)) {
      const color = catColors[cat] || "#888";
      const complete = syms.filter(s => s.status === "complete").map(s => s.normalized);
      const partial = syms.filter(s => s.status === "partial").map(s => `${s.normalized}(${s.synced_count}/${s.total_tfs})`);
      const none = syms.filter(s => s.status === "none").map(s => s.normalized);

      if (complete.length > 0) addLog(`  <span style="color:${color}">${cat}</span> <span style="color:#4caf50">complete:</span> ${complete.join(", ")}`, "#4caf50");
      if (partial.length > 0) addLog(`  <span style="color:${color}">${cat}</span> <span style="color:#ff9800">partial:</span> ${partial.join(", ")}`, "#ff9800");
      if (none.length > 0) addLog(`  <span style="color:${color}">${cat}</span> <span style="color:#666">pending:</span> ${none.join(", ")}`, "#666");
    }
  } catch (e) {
    // BarCacheWriter < v1.300, no specs available — fall back to basic symbol list
    addLog("Specs not available (upgrade BarCacheWriter to v1.300+)", "#888");
  }
}

async function cmdMt5DbSync() {
  const w = createWindow({ title: "MT5 SQLite Direct Sync", width: 700, height: 500 });
  const out = w.element ? w.element.querySelector(".fw-content") : w;
  out.innerHTML = `<div style="padding:8px">
    <div id="mt5db-activity" style="font-family:'Iosevka Fixed',monospace;font-size:11px;color:#888;margin-bottom:6px;border:1px solid #333;border-radius:3px;padding:4px 6px;background:#1a1a1a"></div>
    <div id="mt5db-status" style="font-family:'Iosevka Fixed',monospace;font-size:12px;color:#4caf50;margin-bottom:8px;font-weight:bold">Discovering MT5 databases...</div>
    <div id="mt5db-progress" style="background:#222;border-radius:3px;height:20px;margin-bottom:8px;overflow:hidden">
      <div id="mt5db-bar" style="background:#2196f3;height:100%;width:0%;transition:width 0.3s;border-radius:3px"></div>
    </div>
    <div id="mt5db-stats" style="font-family:'Iosevka Fixed',monospace;font-size:11px;color:#888;margin-bottom:8px"></div>
    <div id="mt5db-specs" style="font-family:'Iosevka Fixed',monospace;font-size:10px;color:#888;margin-bottom:8px"></div>
    <div id="mt5db-log" style="font-family:'Iosevka Fixed',monospace;font-size:10px;color:#666;overflow-y:auto;max-height:250px"></div>
  </div>`;

  const statusEl = out.querySelector("#mt5db-status");
  const barEl = out.querySelector("#mt5db-bar");
  const statsEl = out.querySelector("#mt5db-stats");
  const logDiv = out.querySelector("#mt5db-log");

  const activityEl = out.querySelector("#mt5db-activity");

  const setStatus = (msg, color = "#4caf50") => { statusEl.textContent = msg; statusEl.style.color = color; };
  const setProgress = (pct) => { barEl.style.width = pct + "%"; };
  const setStats = (msg) => { statsEl.textContent = msg; };
  const addLog = (msg, color = "#666") => { logDiv.innerHTML += `<div style="color:${color}">${msg}</div>`; logDiv.scrollTop = logDiv.scrollHeight; };

  // Live per-DB activity display — listens for progress events from Rust sync
  const dbActivity = {}; // instance -> { symbol, tf, current, total }
  let unlisten = null;
  if (window.__TAURI__?.event?.listen) {
    window.__TAURI__.event.listen("mt5-sync-progress", (event) => {
      const d = event.payload;
      dbActivity[d.instance] = d;
      const lines = Object.keys(dbActivity).sort().map(inst => {
        const a = dbActivity[inst];
        return `<span style="color:#2196f3">DB ${inst}:</span> <span style="color:#4caf50">${a.symbol}</span><span style="color:#666">:${a.tf}</span> <span style="color:#888">(${a.current}/${a.total})</span>`;
      });
      activityEl.innerHTML = lines.join("&nbsp;&nbsp;&nbsp;");
    }).then(fn => { unlisten = fn; });
  }
  w.addCleanup(() => { if (unlisten) unlisten(); });

  try {
    const startTime = Date.now();
    const specsDiv = out.querySelector("#mt5db-specs");
    let mt5SymbolList = { count: 0 };
    let syncCount = 0;
    let prevSymCount = 0;
    let prevBarCount = 0;
    let lastGoodSync = null;

    // Helper: run one sync cycle, update all UI elements
    async function doSync() {
      syncCount++;
      const el = ((Date.now() - startTime) / 1000).toFixed(0);

      // Get symbol list
      try {
        mt5SymbolList = JSON.parse(await invoke("get_mt5_symbol_list"));
      } catch (_) {}

      // Run bar sync
      const r = JSON.parse(await invoke("sync_mt5_sqlite"));
      const gotData = r.imported > 0 || (r.skipped || 0) > 0 || r.total_bars > 0;

      if (gotData) {
        setStatus(`Sync #${syncCount} — ${r.symbols} symbols, ${r.total_bars.toLocaleString()} bars`, "#4caf50");
        const dedup = r.deduped ? `, ${r.deduped} deduped` : "";
        setStats(`${r.imported} new + ${r.skipped || 0} unchanged from ${r.databases_read}/${r.databases_found} instances${dedup} | ${el}s`);
        setProgress(100);
        barEl.style.background = "#4caf50";
        lastGoodSync = { ...r, el };

        // Log only meaningful changes
        if (mt5SymbolList.count !== prevSymCount) {
          addLog(`Symbols: ${mt5SymbolList.count} (was ${prevSymCount})`, "#4caf50");
          prevSymCount = mt5SymbolList.count;
        }
        if (r.total_bars > prevBarCount && r.imported > 0) {
          addLog(`+${r.imported} entries (${r.total_bars.toLocaleString()} total bars) from ${r.databases_read}/${r.databases_found} DBs`, "#4caf50");
          prevBarCount = r.total_bars;
        }
      } else if (lastGoodSync) {
        // Fast-path skip (mtime unchanged or concurrent sync) — show last known state
        setStatus(`Sync #${syncCount} — idle (no changes) | ${el}s`, "#4caf50");
        setStats(`Last: ${lastGoodSync.imported || 0} new + ${lastGoodSync.skipped || 0} unchanged from ${lastGoodSync.databases_read || 0}/${lastGoodSync.databases_found || 0} instances`);
        setProgress(100);
        barEl.style.background = "#4caf50";
      } else {
        setStatus(`Waiting for BarCacheWriter — ${r.databases_found} DBs found (${el}s)`, "#ff9800");
        setStats("BarCacheWriter must be compiled + attached in each MT5 instance");
        setProgress(10);
        barEl.style.background = "#ff9800";
      }

      // Always update specs display in-place
      try {
        const specs = JSON.parse(await invoke("get_mt5_specs"));
        renderSpecsToDiv(specsDiv, specs);
      } catch (_) {}

      return gotData;
    }

    // Initial sync
    setStatus("Connecting to MT5 databases...", "#2196f3");
    setProgress(5);
    const hasData = await doSync();

    // Continuous sync loop
    const syncInterval = setInterval(async () => {
      if (!document.body.contains(out)) { clearInterval(syncInterval); return; }
      try { await doSync(); } catch (_) {}
    }, hasData ? 30000 : 10000);

    addLog("Continuous sync active. Close window to stop.", "#2196f3");

  } catch (e) {
    setStatus(`Error: ${e}`, "#f44336");
    setProgress(0);
    barEl.style.background = "#f44336";
    addLog(`${e}`, "#f44336");
  }
}

// ── Background MT5 Sync (headless, controlled by MT5_SYNC setting) ──
let mt5BgSyncInterval = null;
let mt5BgSyncCount = 0;
let lastMt5SyncSuccess = 0;     // epoch ms of last successful MT5 sync (databases_read > 0)
let mt5SymbolSet = new Set();   // symbols known to exist in MT5 cache
const MT5_DISCONNECT_MS = 15 * 60 * 1000; // 15 minutes

// Check if a symbol's data comes from MT5 (true) or Alpaca fallback (false)
function isSymbolMt5(symbol) {
  if (!mt5BgSyncInterval) return false; // MT5 sync not running
  if (mt5SymbolSet.size === 0) return false;
  if (Date.now() - lastMt5SyncSuccess > MT5_DISCONNECT_MS) return false; // disconnected
  return mt5SymbolSet.has(symbol);
}

// MT5 data source label — users configure their MT5 broker via BarCacheWriter
let mt5ServerLabel = "MT5";

// Get data source label for display
function getDataSourceLabel(symbol) {
  if (!mt5BgSyncInterval) return { label: "Alpaca", color: "#ff9800", icon: "A" };
  if (Date.now() - lastMt5SyncSuccess > MT5_DISCONNECT_MS) {
    return { label: mt5ServerLabel + " Disconnected \u2014 Alpaca", color: "#f44336", icon: "!" };
  }
  if (mt5SymbolSet.has(symbol)) {
    return { label: mt5ServerLabel, color: "#4caf50", icon: "M" };
  }
  return { label: "Alpaca", color: "#ff9800", icon: "A" };
}

// Update the data source badge in the status bar
function updateDataSourceBadge(symbol) {
  const sym = symbol || currentSymbol;
  if (!sym) return;
  const statusBar = document.getElementById("connect-status-bar");
  if (!statusBar) return;

  // Remove existing badge
  const existing = statusBar.querySelector(".data-source-badge");
  if (existing) existing.remove();

  const src = getDataSourceLabel(sym);
  const badge = document.createElement("span");
  badge.className = "data-source-badge";
  badge.textContent = src.label;
  badge.style.cssText = `
    margin-left:8px;padding:1px 6px;border-radius:3px;font-size:9px;font-weight:bold;
    color:#000;background:${src.color};opacity:0.85;vertical-align:middle;letter-spacing:0.3px;
  `;
  badge.title = src.icon === "!" ? "MT5 sync has not succeeded in 15+ minutes" : `Data source: ${src.label}`;
  statusBar.appendChild(badge);
}

async function refreshMt5SymbolList() {
  try {
    const list = JSON.parse(await invoke("list_mt5_symbols"));
    if (Array.isArray(list) && list.length > 0) {
      const symbols = new Set();
      for (const entry of list) {
        if (!entry.symbol) continue;
        if (entry.symbol === "__SERVER__") {
          // __SERVER__ key stores broker identity as JSON in the cache data
          // The key is stored by list_mt5_symbols; actual data needs a cache read
          continue;
        }
        if (!entry.symbol.startsWith("__")) symbols.add(entry.symbol);
      }
      if (symbols.size > 0) mt5SymbolSet = symbols;
    }
  } catch (_) {}

  // Read broker name from __SERVER__ metadata in cache
  try {
    const statsJson = await invoke("db_cache_detailed_stats");
    const stats = JSON.parse(statsJson);
    if (Array.isArray(stats)) {
      for (const entry of stats) {
        const key = Array.isArray(entry) ? entry[0] : entry.key;
        if (key && key.includes("__SERVER__")) {
          const json = await invoke("db_cache_get", { key });
          if (json) {
            try {
              const meta = JSON.parse(json);
              if (meta && meta.company) {
                mt5ServerLabel = "MT5 (" + meta.company + ")";
                break;
              } else if (meta && meta.server) {
                mt5ServerLabel = "MT5 (" + meta.server + ")";
                break;
              }
            } catch (_) {}
          }
        }
      }
    }
  } catch (_) {}
}

async function handleMt5SyncResult(r) {
  // Mark MT5 as healthy if we read any databases OR have any bars cached
  if (r.databases_read > 0 || r.total_bars > 0 || (r.skipped || 0) > 0) lastMt5SyncSuccess = Date.now();
  if (r.imported > 0) {
    // Refresh symbol list when new data arrives
    await refreshMt5SymbolList();
    // Invalidate in-memory cache for current symbol and reload chart
    if (currentSymbol) {
      for (const key of Object.keys(barCache)) {
        if (key.startsWith(currentSymbol + ":")) {
          delete barCache[key];
        }
      }
      loadChart(currentSymbol, currentTimeframe);
    }
  }
  updateDataSourceBadge();
}

async function startMt5BackgroundSync() {
  if (mt5BgSyncInterval) return; // already running
  // Load MT5 symbol list on startup
  await refreshMt5SymbolList();
  try {
    const r = JSON.parse(await invoke("sync_mt5_sqlite"));
    mt5BgSyncCount++;
    if (r.imported > 0) {
      console.log(`[MT5 Sync #${mt5BgSyncCount}] ${r.imported} new, ${r.skipped} unchanged, ${r.deduped || 0} deduped, ${r.total_bars} bars from ${r.databases_read}/${r.databases_found} DBs`);
    }
    await handleMt5SyncResult(r);
  } catch (e) {
    console.warn("[MT5 Sync] initial:", e);
  }
  mt5BgSyncInterval = setInterval(async () => {
    try {
      const r = JSON.parse(await invoke("sync_mt5_sqlite"));
      mt5BgSyncCount++;
      if (r.imported > 0) {
        console.log(`[MT5 Sync #${mt5BgSyncCount}] ${r.imported} new, ${r.total_bars} bars`);
      }
      await handleMt5SyncResult(r);
    } catch (_) {}
  }, 30000);
  console.log("[MT5 Sync] Background sync started (30s interval)");
}

function stopMt5BackgroundSync() {
  if (mt5BgSyncInterval) {
    clearInterval(mt5BgSyncInterval);
    mt5BgSyncInterval = null;
    console.log("[MT5 Sync] Background sync stopped");
  }
}

// ── Kraken Weekend Crypto Sync ──────────────────────────────────────
let krakenWeekendSyncInterval = null;

function isCryptoSymbol(sym) {
  if (!sym) return false;
  // "BTC/USD", "ETH/USD" style or CRYPTO_MAP values
  if (sym.includes("/") && sym.endsWith("USD")) return true;
  // Check CRYPTO_MAP keys (bare tickers like "BTC")
  if (CRYPTO_MAP[sym]) return true;
  // Common crypto pairs without slash: BTCUSD, ETHUSD, etc.
  const cryptoBases = ["BTC", "ETH", "SOL", "DOGE", "ADA", "XRP", "DOT", "AVAX", "LINK", "MATIC", "UNI", "SHIB", "LTC", "BCH", "AAVE", "SUSHI", "ATOM"];
  for (const base of cryptoBases) {
    if (sym === base + "/USD" || sym === base + "USD") return true;
  }
  return false;
}

function isMarketWeekend() {
  const now = new Date();
  const utcDay = now.getUTCDay(); // 0=Sun, 6=Sat
  const utcHour = now.getUTCHours();
  // Forex/stock markets closed: Friday 22:00 UTC to Sunday 22:00 UTC
  if (utcDay === 6) return true; // all Saturday
  if (utcDay === 0 && utcHour < 22) return true; // Sunday before 22:00 UTC
  if (utcDay === 5 && utcHour >= 22) return true; // Friday after 22:00 UTC
  return false;
}

async function krakenWeekendSyncTick() {
  const sym = currentSymbol;
  if (!sym || !isCryptoSymbol(sym)) return;
  if (!isMarketWeekend()) return;
  const tf = currentTimeframe || "1Day";
  const oneWeekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().slice(0, 10);
  try {
    const r = JSON.parse(await invoke("fetch_binance_bars", { symbol: sym, timeframe: tf, startDate: oneWeekAgo }));
    if (r.bars > 0) {
      console.log(`[Kraken Weekend Sync] ${sym} @ ${tf}: ${r.bars} bars (${r.first} -> ${r.last})`);
      // Invalidate hot cache so next render picks up new data
      const cacheKey = getCacheKey(sym, tf);
      delete barCache[cacheKey];
      // Refresh chart if still on same symbol
      if (currentSymbol === sym && currentTimeframe === tf) {
        loadChart(sym, tf);
      }
    }
  } catch (e) {
    console.warn("[Kraken Weekend Sync]", e);
  }
}

function startKrakenWeekendSync() {
  if (krakenWeekendSyncInterval) return;
  // Do an immediate tick, then every 30s
  krakenWeekendSyncTick();
  krakenWeekendSyncInterval = setInterval(krakenWeekendSyncTick, 30000);
  console.log("[Kraken Weekend Sync] Started (30s interval)");
}

function stopKrakenWeekendSync() {
  if (krakenWeekendSyncInterval) {
    clearInterval(krakenWeekendSyncInterval);
    krakenWeekendSyncInterval = null;
    console.log("[Kraken Weekend Sync] Stopped");
  }
}

